import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.DTiDeF2Q.js";const x=JSON.parse('{"title":"Аліаси Tmux | Dotfiles (UK)","titleTemplate":":title","description":"Короткі команди tmux. Огляд для Dotfiles v0.2.495. Сумісно з macOS, Linux та WSL через Dotfiles.","frontmatter":{"title":"Аліаси Tmux | Dotfiles","description":"Короткі команди tmux. Огляд для Dotfiles v0.2.495. Сумісно з macOS, Linux та WSL через Dotfiles.","lang":"uk-UA","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Аліаси Tmux | Dotfiles preview","canonical":"/uk/aliases/tmux/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Аліаси Tmux","pageType":"docs","schemaType":"WebPage","permalink":"/uk/aliases/tmux/"},"headers":[],"relativePath":"uk/aliases/tmux/index.md","filePath":"uk/aliases/tmux/index.md","lastUpdated":1773010926000}'),l={name:"uk/aliases/tmux/index.md"};function s(d,e,c,u,m,n){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="аліаси-tmux" tabindex="-1">Аліаси Tmux <a class="header-anchor" href="#аліаси-tmux" aria-label="Permalink to &quot;Аліаси Tmux&quot;">​</a></h1><p>Короткі команди tmux.</p><p>Ця сторінка знайомить з однією групою аліасів та її поширеними скороченнями команд. Прочитайте її спочатку, щоб зрозуміти угоди про іменування, очікувані вхідні дані та безпечні шаблони виконання. Потім відкрийте довідковий додаток для повного переліку команд та точного синтаксису. Ці аліаси зменшують повторний набір та зберігають послідовну поведінку робочого процесу на macOS, Linux та WSL.</p><h2 id="коли-використовувати" tabindex="-1">Коли використовувати <a class="header-anchor" href="#коли-використовувати" aria-label="Permalink to &quot;Коли використовувати&quot;">​</a></h2><p>Використовуйте цю сторінку перед щоденною роботою в оболонці, коли вам потрібні передбачувані шаблони команд.</p><h2 id="що-включено" tabindex="-1">Що включено <a class="header-anchor" href="#що-включено" aria-label="Permalink to &quot;Що включено&quot;">​</a></h2><ul><li>Аліаси: 11</li><li>Допоміжні функції: 1</li><li>Файли джерел: 1</li></ul><h2 id="швидкі-приклади" tabindex="-1">Швидкі приклади <a class="header-anchor" href="#швидкі-приклади" aria-label="Permalink to &quot;Швидкі приклади&quot;">​</a></h2><ul><li><code>tma</code> → <code>&#39;tmux attach-session&#39; # Приєднатися до останньої сесії</code></li><li><code>tmat</code> → <code>&#39;tmux attach-session -t&#39; # Приєднатися до конкретної сесії</code></li><li><code>tmi</code> → <code>&#39;tmux info&#39; # Показати інформацію tmux</code></li><li><code>tmka</code> → <code>&#39;tmux kill-server&#39; # Завершити всі сесії (сервер)</code></li><li><code>tmks</code> → <code>&#39;tmux kill-session -a&#39; # Завершити всі сесії крім поточної</code></li><li><code>tml</code> → <code>&#39;tmux list-sessions&#39; # Список всіх сесій</code></li><li><code>tmlp</code> → <code>&#39;tmux list-panes&#39; # Список панелей</code></li><li><code>tmls</code> → <code>&#39;tmux list-windows&#39; # Список вікон</code></li><li><code>tmn</code> → <code>&#39;tmux new-session&#39; # Нова безіменна сесія</code></li><li><code>tmr</code> → <code>&#39;tmux source ~/.dotfiles/lib/configurations/tmux/tmux&#39; # Перезавантажити конфіг</code></li><li><code>tms</code> → <code>&#39;tmux new-session -s&#39; # Нова іменована сесія</code></li></ul><h2 id="наступнии-крок" tabindex="-1">Наступний крок <a class="header-anchor" href="#наступнии-крок" aria-label="Permalink to &quot;Наступний крок&quot;">​</a></h2><p>Відкрити повний перелік:</p>',11)])])}const p=t(l,[["render",s]]);export{x as __pageData,p as default};
